(window.webpackJsonp=window.webpackJsonp||[]).push([[145],{666:function(n,t,e){"use strict";e.r(t);var a=e(29),o=Object(a.a)({},(function(){var n=this,t=n.$createElement,e=n._self._c||t;return e("ContentSlotsDistributor",{attrs:{"slot-key":n.$parent.slotKey}},[e("p",[n._v("思维导图：https://www.processon.com/view/5d0750d9e4b024123ddd84d8#map")]),n._v(" "),e("p",[n._v("https://blog.csdn.net/lv8549510/article/details/85406215\nlinux权限详解")]),n._v(" "),e("p",[n._v("https://blog.csdn.net/aaznl/article/details/106439091?utm_medium=distribute.wap_relevant.none-task-blog-BlogCommendFromMachineLearnPai2-1.wap_blog_relevant_pic&depth_1-utm_source=distribute.wap_relevant.none-task-blog-BlogCommendFromMachineLearnPai2-1.wap_blog_relevant_pic\nlinux文件权限与归属详解")]),n._v(" "),e("p",[n._v('关于权限\n对于权限我们通常都会存在三个角色\n权限使用者\n权限角色\n权限使用目标\nLinux 权限设计\n在Linux 中权限使用者为账户\n由于一切皆为文件，那么权限目标为文件\n对于一个文件或目录来说，Linux 对应三个角色  ”天神Root用户“，”文件拥有者“，”文件所属分组“，”其他用户“\nLinux中角色理解\n文件目录权限\n概述\n对于每一种角色都对应一组权限，分别为RWX\n文件的 RWX\nR权限\n可读取此一文件的实际内容，如读取文本文件的文字内容\nW权限\n可以编辑、新增或者是修改该文件的内容（但不含删除该文件）\nX权限\n该文件具有可以被系统执行的权限\n目录的权限\nR权限\n表示你可以查询该目录下的文件名数据\nW权限\n表示你具有异动该目录结构清单的权限\n创建新的文件与目录；\n删除已经存在的文件与目录\n将已存在的文件或目录进行更名\n搬移该目录内的文件、目录位置\nX权限\n表示的是使用者能否进入或打开目录的权限\n权限动作对应关系\n当我们需要对目录中文件做读，改，执行，复制等操作的前提是需要能够获得该目录进入权限 x\n删除目录中文件只需要获取目录的wx权限，无需文件相关权限\n案例\n目录相关操作\n仅仅只具有目录的r权限，不具有x权限无法使用ls查看完整目录结构属性信息\n拥有目录rx权限可以使用ls查看完整目录结构属性信息\n仅仅只具有目录的w权限，不具有x权限无法rm删除目录中的文件（修改目录结构）\n拥有目录wx权限可以使用rm删除目录中的文件（修改目录结构）\n文件相关操作\n仅仅具有文件r,权限不具有文件所有目录x权限无法读取文件内容\n仅仅具有文件w权限和目录x权限，不具有文件r权限\n使用echo "" > 文件可以写入成功\n使用vim编辑器需要 wq!强制写入\n仅仅具有文件x权限和目录x权限,不具有文件r权限无法执行文件\nLinux中存储用户，分组信息文件\n/etc/passwd\n账号信息\n/etc/shadow\n账号密码信息\n/etc/group\n群组名称信息\n权限管理命令\nchgrp ：改变文件所属群组\n用法\nchgrp [-R] dirname/filename ...\n选项与参数\n-R : 进行递回（recursive）的持续变更，亦即连同次目录下的所有文件、目录 都更新成为这个群组之意。常常用在变更某一目录内所有的文件之情况\n案例\n修改用户所属群组\n注意\n设置群组必须存在\nchown ：改变文件拥有者\n用法\nchown [-R] 帐号名称 文件或目录\nchown [-R] 帐号名称:群组名称 文件或目录\nchown 可以同时改变文件所属的群组和文件拥有者\n选项参数\n-R : 进行递回（recursive）的持续变更，亦即连同次目录下的所有文件都变更\n案例\n将 initial-setup-ks.cfg 的拥有者改为bin这个帐号\n将 initial-setup-ks.cfg 的拥有者与群组改回为root\n注意\n设置用户必须存在\nchmod ：改变文件的权限\n数字类型改变文件权限\n用法\nchmod [-R] xyz 文件或目录\nx 表示文件拥有者的权限\ny 表示文件所属组的权限\nz 表示其他人的权限\n读取权限=4，写入权限=2，执行权限=1，权限x,y,z等于其数字相加\n案例\n将.bashrc这个文件所有的权限都设置启用\n符号类型改变文件权限\n用法\n| chmod | u g o a |   +（加入）  -（除去）   =（设置） | r w x | 文件或目录 |\nu  表示文件拥有者的权限\ng  表示文件所属组的权限\no 表示其他人的权限\na 表示所有的权限\n案例\n用户拥有者添加rwx，分组和其他人设置为rx\n文件默认权限：umask\n什么时umask\numask 就是指定 “目前使用者在创建文件或目录时候的权限默认值\n查看 umask\n显示数字 umask\n[root@localhost tmp]# umask 0022\n我们知道权限时按照分数计算的如 r、w、x 分别是 4、2、1 分\n上面的4个数字分别表示 特殊权限，文件拥有者权限，文件分组权限，其他人权限\n这里022表示是要减去的分数！！\n因而上创建的文件目录的权限为    rwxr-xr-x\n显示字符 umask\n[root@localhost tmp]# umask -S u=rwx,g=rx,o=rx\n设置umask\numask 数字')]),n._v(" "),e("div",{staticClass:"language- extra-class"},[e("pre",[e("code",[n._v("   1、linux文件或目录的权限分为读、写、可执行三种权限。文件访问的用户类别分为，文件创建者、与文件创建者同组的用户、其他用户三类。\n")])])]),e("p",[n._v("2、修改文件的权限或目录的命令为“chmod 755 test.sh”。755表示“创建者拥有读写可执行权限、同一组用户以及其他用户拥有读和执行权限”。\n　　\n　　3、“755”怎么构成的：“0”表示没有权限、“1”表示可执行权限、“2”表示可写权限、“4”表示可读权限。\n　　\n　　4、使用“chmod 777 test.sh”命令使用能使用linux系统的用户拥有相同的“读写可执行权限”。\n　　\n　　5、linux给文件或目录赋权限还有一种容易理解方法。比如：“chmod a-x”表示所有用户对此文件或目录将没有执行权限。\n　　\n　　6、“a”表示所有用户，“u”表示创建者、“g”表示创建者同组用户、“o”表示其他用户；“+”表示添加权限，“-”表示取消权限；“r”表示读权限、“w”表示写权限、“x”表示写权限。")])])}),[],!1,null,null,null);t.default=o.exports}}]);